// ── Shared UI components ──────────────────────────────────────────────────────
function ProgressBar({ step, total }) {
  const pct = Math.round((step / total) * 100);
  return (
    <div style={{ marginBottom: 24 }}>
      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: "#666", marginBottom: 6 }}>
        <span>Step {step} of {total}</span><span>{pct}%</span>
      </div>
      <div style={{ height: 6, background: "#e5e7eb", borderRadius: 99 }}>
        <div style={{ height: 6, borderRadius: 99, background: PRIMARY, width: pct + "%", transition: "width 0.4s ease" }} />
      </div>
    </div>
  );
}

function SectionHeader({ icon, title, subtitle }) {
  return (
    <div style={{ marginBottom: 24 }}>
      <div style={{ fontSize: 32, marginBottom: 8 }}>{icon}</div>
      <h2 style={{ margin: 0, fontSize: 22, fontWeight: 700, color: PRIMARY }}>{title}</h2>
      {subtitle && <p style={{ margin: "6px 0 0", color: "#555", fontSize: 14 }}>{subtitle}</p>}
    </div>
  );
}

function InfoCard({ children, accent }) {
  return (
    <div style={{ background: accent ? "#f0f9f5" : "#f8f9fa", border: `1px solid ${accent ? ACCENT : "#e5e7eb"}`, borderLeft: `4px solid ${accent ? ACCENT : PRIMARY}`, borderRadius: 8, padding: "14px 16px", marginBottom: 14, fontSize: 14, color: "#333" }}>
      {children}
    </div>
  );
}

function CheckItem({ label, checked, onChange }) {
  return (
    <label style={{ display: "flex", alignItems: "flex-start", gap: 12, marginBottom: 12, cursor: "pointer", fontSize: 14, color: "#333" }}>
      <div onClick={onChange} style={{ width: 22, height: 22, minWidth: 22, border: `2px solid ${checked ? PRIMARY : "#cbd5e1"}`, borderRadius: 4, background: checked ? PRIMARY : "#fff", display: "flex", alignItems: "center", justifyContent: "center", marginTop: 1, transition: "all 0.2s" }}>
        {checked && <span style={{ color: "#fff", fontSize: 14, fontWeight: 700 }}>✓</span>}
      </div>
      <span>{label}</span>
    </label>
  );
}

function NavButtons({ onBack, onNext, nextLabel = "Continue", nextDisabled }) {
  return (
    <div style={{ display: "flex", gap: 12, marginTop: 28 }}>
      {onBack && <button onClick={onBack} style={{ flex: 1, padding: "12px 0", borderRadius: 8, border: `2px solid ${PRIMARY}`, background: "#fff", color: PRIMARY, fontWeight: 600, fontSize: 15, cursor: "pointer" }}>← Back</button>}
      <button onClick={onNext} disabled={nextDisabled} style={{ flex: 2, padding: "12px 0", borderRadius: 8, border: "none", background: nextDisabled ? "#cbd5e1" : PRIMARY, color: "#fff", fontWeight: 700, fontSize: 15, cursor: nextDisabled ? "not-allowed" : "pointer", transition: "background 0.2s" }}>{nextLabel} →</button>
    </div>
  );
}

